const b = ($input.first().json.body || $input.first().json);
if (!b.orderId) throw new Error('orderId ausente');
if (!b.spa_id)  throw new Error('spa_id ausente');
return [{ json: {
  spa_id:      String(b.spa_id),
  orderId:     String(b.orderId),
  category_id: b.category_id || 730,
} }];

const crypto  = require('crypto');
const orderId = $json.orderId;
const path    = '/v3/orders/' + orderId;
const ts      = Date.now().toString();
const raw     = ts + '\r\nGET\r\n' + path + '\r\n\r\n';
const sig     = crypto.createHmac('sha256','sk_prod_v30Ci06vXqPeizCg6e461VZEymmFzMDAXZQwTm3NdYcwyLaS8nxrQEX0JKcp0mAM').update(raw).digest('hex');
return [{ json: { ...$json,
  _auth: 'hmac pk_prod_d38621223012b9ec71d0634589126e3b:' + ts + ':' + sig,
  _url:  'https://rest.lalamove.com' + path,
} }];

const o = $('📦 GET Order').first().json;
const d = $('📥 Parse Input').first().json;

// A resposta real é: { data: { stops: [...] } }
const stops = (o.data?.stops || o.stops || []);
if (!stops.length) throw new Error('Nenhum stop retornado para orderId=' + d.orderId);

// ── Stop 0 = COLETA → campo POP
const firstStop = stops[0] || {};
const popImages  = firstStop.POP?.imageUrls || [];   // array de URLs
const pickedUpAt = firstStop.POP?.pickedUpAt || '';  // ISO timestamp

// ── Stop final = ENTREGA → campo POD
const lastStop    = stops[stops.length - 1] || {};
const podImage    = lastStop.POD?.image || '';         // URL única (string)
const deliveredAt = lastStop.POD?.deliveredAt || '';  // ISO timestamp
const podStatus   = lastStop.POD?.status || '';       // 'DELIVERED'

const hasPOD = !!podImage;
const hasPOP = popImages.length > 0;

const token = $env.B24_TOKEN;
if (!token) throw new Error('B24_TOKEN não configurado em n8n → Settings → Variables');

// ── Montar texto do comentário de timeline
const lines = ['📦 Pedido Lalamove concluído — ' + d.orderId];
if (hasPOP) {
  lines.push('');
  lines.push('📷 Foto de Coleta (POP):');
  popImages.forEach((url, i) => lines.push('  ' + (i+1) + '. ' + url));
  if (pickedUpAt) lines.push('  ⏱ Coletado em: ' + pickedUpAt);
}
if (hasPOD) {
  lines.push('');
  lines.push('✅ Foto de Entrega (POD):');
  lines.push('  ' + podImage);
  if (deliveredAt) lines.push('  ⏱ Entregue em: ' + deliveredAt);
}
if (!hasPOP && !hasPOD) lines.push('⚠️ Sem fotos registradas.');
const commentText = lines.join('\n');

const B24 = 'https://promobrindes.bitrix24.com.br/rest/1/' + token;

return [{ json: {
  orderId:      d.orderId,
  spa_id:       d.spa_id,
  category_id:  d.category_id || 730,
  // POP
  popImages, pickedUpAt, hasPOP,
  // POD
  podImage, deliveredAt, podStatus, hasPOD,
  // Texto timeline
  commentText,
  // URLs Bitrix24
  _update_url:   B24 + '/crm.item.update',
  _update_body:  JSON.stringify({
    entityTypeId: 1690,
    id: parseInt(d.spa_id),
    fields: {
      stageId:               'DT1690_' + (d.category_id || 730) + ':WON',
      ufCrm276_1760014914:   'Y',
      ufCrm276_1760015259:   hasPOD ? 'Y' : 'N',
    }
  }),
  _comment_url:  B24 + '/crm.timeline.comment.add',
  _comment_body: JSON.stringify({
    fields: {
      ENTITY_TYPE: 'dynamic_1690',
      ENTITY_ID:   parseInt(d.spa_id),
      COMMENT:     commentText,
    }
  }),
} }];
